// MARK: - Account Model

class Account: Codable {
    let id: UUID
    let accountNumber: String
    var balance: Decimal
    var transactions: [Transaction]

    init(id: UUID = UUID(), accountNumber: String, initialBalance: Decimal) {
        self.id = id
        self.accountNumber = accountNumber
        self.balance = initialBalance
        self.transactions = []
    }

    func addTransaction(_ transaction: Transaction) {
        transactions.insert(transaction, at: 0) // Add to the beginning for latest first
    }
}

